const articles = $input.first().json?.articles || [];

const alerts = articles
  .filter(a => a.title && a.title !== '[Removed]')
  .map(a => {
    return {
      json: {
        title: `📰 ${a.title}`,
        summary: a.description || a.content?.substring(0, 200) || '',
        source: 'NewsAPI',
        source_url: a.url || '',
        image_url: a.urlToImage || null,
        severity: 'green',
        event_type: 'news',
        latitude: null,
        longitude: null,
        country: null,
        source_id: `newsapi-${Buffer.from(a.url || a.title).toString('base64').substring(0, 50)}`
      }
    };
  });

return alerts.length > 0 ? alerts : [{ json: { _skip: true } }];
